using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using System.Data.SqlClient;
using System.Security.Cryptography;
using Microsoft.Extensions.Configuration;

namespace AzureFunctionWithLogging
{
    public static class SecureFunction
    {
        private static readonly HashSet<string> AllowedHeaders = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "Authorization", "Content-Type", "User-Agent", "Accept", "Accept-Language"
        };

        private static readonly HashSet<string> AllowedQueryParams = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "id", "filter", "page"
        };

        [FunctionName("SecureFunction")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
            ILogger log,
            ExecutionContext context)
        {
            var config = new ConfigurationBuilder()
                .SetBasePath(context.FunctionAppDirectory)
                .AddJsonFile("local.settings.json", optional: true, reloadOnChange: true)
                .AddEnvironmentVariables()
                .Build();

            var functionName = context.FunctionName;
            var correlationId = Guid.NewGuid().ToString();

            try
            {
                log.LogInformation($"Function '{functionName}' triggered. Correlation ID: {correlationId}");

                LogHttpRequestHeaders(req, log, correlationId);
                await LogHttpRequestBody(req, log, correlationId);

                var queryParams = req.Query
                    .Where(p => AllowedQueryParams.Contains(p.Key))
                    .ToDictionary(p => p.Key, p => p.Value.ToString());

                log.LogInformation($"Query Parameters: {JsonConvert.SerializeObject(queryParams)}");

                var userContext = ExtractUserContext(req, log, correlationId);
                log.LogInformation($"User Context: {JsonConvert.SerializeObject(userContext)}");

                var dbConnection = config["DatabaseConnectionString"];
                if (string.IsNullOrEmpty(dbConnection))
                {
                    throw new InvalidOperationException("Database connection string not configured");
                }

                var query = req.Query["query"].ToString();
                if (string.IsNullOrEmpty(query))
                {
                    throw new ArgumentException("Query parameter is required");
                }

                var parameters = new Dictionary<string, object>();
                if (req.Form.Any())
                {
                    foreach (var formItem in req.Form)
                    {
                        if (formItem.Key != "password" && formItem.Key != "token")
                        {
                            parameters[formItem.Key] = formItem.Value.ToString();
                        }
                    }
                }

                log.LogInformation($"Executing database query: {query}");
                log.LogInformation($"Query parameters: {JsonConvert.SerializeObject(parameters)}");

                var result = await ExecuteDatabaseQuery(dbConnection, query, parameters, log, correlationId);
                log.LogInformation($"Database query completed successfully. Result count: {result.Count}");

                return new OkObjectResult(result);
            }
            catch (Exception ex)
            {
                log.LogError($"Exception in function '{functionName}': {ex.Message}");
                log.LogError($"Exception details: {ex}");
                log.LogError($"Stack trace: {ex.StackTrace}");
                log.LogError($"Correlation ID: {correlationId}");

                return new StatusCodeResult(500);
            }
        }

        private static void LogHttpRequestHeaders(HttpRequest req, ILogger log, string correlationId)
        {
            var headers = new Dictionary<string, string>();
            foreach (var header in req.Headers)
            {
                if (AllowedHeaders.Contains(header.Key))
                {
                    headers[header.Key] = header.Value.ToString();
                }
            }
            log.LogInformation($"Request Headers: {JsonConvert.SerializeObject(headers)}");
        }

        private static async Task LogHttpRequestBody(HttpRequest req, ILogger log, string correlationId)
        {
            if (req.ContentLength > 0)
            {
                using (var reader = new StreamReader(req.Body, Encoding.UTF8, true, 1024, true))
                {
                    var body = await reader.ReadToEndAsync();
                    log.LogInformation($"Request Body: {body}");
                }
            }
        }

        private static Dictionary<string, object> ExtractUserContext(HttpRequest req, ILogger log, string correlationId)
        {
            var userContext = new Dictionary<string, object>();
            var authHeader = req.Headers["Authorization"].ToString();

            if (!string.IsNullOrEmpty(authHeader) && authHeader.StartsWith("Bearer "))
            {
                var token = authHeader.Substring(7);
                userContext["TokenHash"] = HashToken(token);
            }

            var userId = req.Headers["X-User-ID"].ToString();
            if (!string.IsNullOrEmpty(userId))
            {
                userContext["UserId"] = userId;
            }

            return userContext;
        }

        private static string HashToken(string token)
        {
            using (var sha256 = SHA256.Create())
            {
                var hashedBytes = sha256.ComputeHash(Encoding.UTF8.GetBytes(token));
                return Convert.ToBase64String(hashedBytes);
            }
        }

        private static async Task<List<Dictionary<string, object>>> ExecuteDatabaseQuery(
            string connectionString,
            string query,
            Dictionary<string, object> parameters,
            ILogger log,
            string correlationId)
        {
            var result = new List<Dictionary<string, object>>();

            try
            {
                using (var connection = new SqlConnection(connectionString))
                {
                    await connection.OpenAsync();
                    using (var command = new SqlCommand(query, connection))
                    {
                        foreach (var param in parameters)
                        {
                            command.Parameters.AddWithValue(param.Key, param.Value ?? DBNull.Value);
                        }

                        using (var reader = await command.ExecuteReaderAsync())
                        {
                            while (await reader.ReadAsync())
                            {
                                var row = new Dictionary<string, object>();
                                for (int i = 0; i < reader.FieldCount; i++)
                                {
                                    row[reader.GetName(i)] = reader.GetValue(i);
                                }
                                result.Add(row);
                            }
                        }
                    }
                }
            }
            catch (SqlException sqlEx)
            {
                log.LogError($"SQL Exception: {sqlEx.Message}");
                log.LogError($"SQL Error Number: {sqlEx.Number}");
                log.LogError($"SQL Procedure: {sqlEx.Procedure}");
                log.LogError($"SQL Line Number: {sqlEx.LineNumber}");
                throw;
            }
            catch (Exception ex)
            {
                log.LogError($"Database execution failed: {ex.Message}");
                throw;
            }

            return result;
        }
    }
